/* ---------------------------------------- *\
 *  合作社数据存储层
 *  使用 Storage 缓存 + HttpDB 持久化
\* ---------------------------------------- */

import { Storage } from "../libs/Storage";

// ===== 类型定义 =====

export interface CoopMember {
  name: string;
  isop: boolean;
}

export interface CoopData {
  cid: string;
  name: string;
  members: CoopMember[];
  notice: string;
  money: number;
  moneylist: string;
}

export interface ShopItem {
  name: string;
  id: string;
  time: number;
  type: number;
  groups: string[];
  des: string;
  num: number;
  sv: number;
  money: number;
  cid: string;
  isTrue: boolean;
  item: { nbt: string; type: string; aux: number };
}

export interface ShopGroup {
  groupid: string;
  displayname: string;
  displaydescribe?: string;
  icon?: string;
  type_function?: {
    type_enum?: string[];
    mode_enum?: string[];
    type_reg_enum?: string[];
  };
}

export interface CooperativeConfig {
  main: { language: string; compare_language: string };
  shop_setting: {
    monetary_unit: string;
    nbtgoods_condition: { type_enum: string[]; mode_enum: string[]; type_reg_enum: string[] };
  };
}

export class Database {
  // ==========================================
  //  内部工具
  // ==========================================

  private static KEY_COOP_DATA = "coop:data";
  private static KEY_COOP_CONFIG = "coop:config";
  private static KEY_SHOP_GOODS = "coop:shopgoods";
  private static KEY_SHOP_GROUPS = "coop:shopgroups";
  private static _config: CooperativeConfig | null = null;

  private static readJSON<T>(key: string, fallback: T): T {
    return Storage.get<T>(key, fallback);
  }

  private static writeJSON(key: string, value: any) {
    Storage.set(key, value);
  }

  // ==========================================
  //  配置
  // ==========================================

  static getConfig(): CooperativeConfig {
    if (this._config) return this._config;
    this._config = this.readJSON(this.KEY_COOP_CONFIG, {
      main: { language: "zh_CN", compare_language: "zh" },
      shop_setting: {
        monetary_unit: "¥",
        nbtgoods_condition: {
          type_enum: ["minecraft:writable_book", "minecraft:field_masoned_banner_pattern", "minecraft:filled_map"],
          mode_enum: ["it.isEnchanted"],
          type_reg_enum: ["[a-z].+_shulker_box"],
        },
      },
    });
    return this._config;
  }

  static saveConfig(cfg: CooperativeConfig) {
    this._config = cfg;
    this.writeJSON(this.KEY_COOP_CONFIG, cfg);
  }

  // ==========================================
  //  合作社数据
  // ==========================================

  static getAllCoop(): CoopData[] {
    return this.readJSON<CoopData[]>(this.KEY_COOP_DATA, []);
  }

  static getCoopByCid(cid: string): CoopData | undefined {
    return this.getAllCoop().find((e) => e.cid === cid);
  }

  static getPlayerCid(playerName: string): string | null {
    for (const coop of this.getAllCoop()) {
      if (coop.members.some((m) => m.name === playerName)) return coop.cid;
    }
    return null;
  }

  static saveCoop(data: CoopData) {
    const all = this.getAllCoop();
    const idx = all.findIndex((e) => e.cid === data.cid);
    if (idx !== -1) all[idx] = data;
    else all.push(data);
    this.writeJSON(this.KEY_COOP_DATA, all);
  }

  static deleteCoop(cid: string) {
    this.writeJSON(this.KEY_COOP_DATA, this.getAllCoop().filter((e) => e.cid !== cid));
  }

  // ==========================================
  //  商店商品
  // ==========================================

  static getAllGoods(): ShopItem[] {
    return this.readJSON<ShopItem[]>(this.KEY_SHOP_GOODS, []);
  }

  static getGoodById(id: string): ShopItem | undefined {
    return this.getAllGoods().find((e) => e.id === id);
  }

  static saveGood(good: ShopItem) {
    const all = this.getAllGoods();
    const idx = all.findIndex((e) => e.id === good.id);
    if (idx !== -1) all[idx] = good;
    else {
      good.id = good.id || `${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
      all.push(good);
    }
    this.writeJSON(this.KEY_SHOP_GOODS, all);
  }

  static deleteGood(id: string) {
    this.writeJSON(this.KEY_SHOP_GOODS, this.getAllGoods().filter((e) => e.id !== id));
  }

  static deleteGoodsByCid(cid: string) {
    this.writeJSON(this.KEY_SHOP_GOODS, this.getAllGoods().filter((e) => e.cid !== cid));
  }

  // ==========================================
  //  商店分组
  // ==========================================

  static getAllGroups(): ShopGroup[] {
    return this.readJSON<ShopGroup[]>(this.KEY_SHOP_GROUPS, []);
  }

  static getGroupById(groupid: string): ShopGroup | undefined {
    return this.getAllGroups().find((e) => e.groupid === groupid);
  }

  static saveGroup(group: ShopGroup) {
    const all = this.getAllGroups();
    const idx = all.findIndex((e) => e.groupid === group.groupid);
    if (idx !== -1) all[idx] = group;
    else all.push(group);
    this.writeJSON(this.KEY_SHOP_GROUPS, all);
  }

  // ==========================================
  //  初始化
  // ==========================================

  static initDefaultGroups() {
    if (this.getAllGroups().length > 0) return;

    const defaults: ShopGroup[] = [
      { groupid: "default_block", displayname: "默认方块", displaydescribe: "方块类物品", icon: "/textures/ui/icon_recipe_construction", type_function: { mode_enum: ["default_block"] } },
      { groupid: "default_item", displayname: "默认物品", displaydescribe: "物品类", icon: "/textures/ui/icon_recipe_item", type_function: { mode_enum: ["default_item"] } },
      { groupid: "default_equip", displayname: "默认装备", displaydescribe: "装备武器类", icon: "/textures/ui/icon_recipe_equipment", type_function: { type_enum: ["minecraft:bow", "minecraft:arrow", "minecraft:crossbow", "minecraft:trident", "minecraft:shield", "minecraft:mace", "minecraft:elytra", "minecraft:wolf_armor", "minecraft:saddle"], type_reg_enum: ["[a-z].+_shovel", "[a-z].+_axe", "[a-z].+_sword", "[a-z].+_hoe", "[a-z].+_pickaxe", "[a-z].+_horse_armor"] } },
      { groupid: "default_book", displayname: "书籍", displaydescribe: "与书相关", icon: "/textures/items/book_enchanted", type_function: { type_enum: ["minecraft:book", "minecraft:bookshelf", "minecraft:writable_book", "minecraft:enchanted_book", "minecraft:chiseled_bookshelf"] } },
      { groupid: "default_shulker_box", displayname: "潜影盒", displaydescribe: "各种潜影盒", icon: "/textures/items/shulker_shell", type_function: { type_reg_enum: ["[a-z].+_shulker_box"] } },
      { groupid: "default_potion", displayname: "药水", displaydescribe: "药水类", icon: "/textures/items/potion_bottle_heal", type_function: { type_enum: ["minecraft:splash_potion", "minecraft:potion", "minecraft:lingering_potion"] } },
    ];
    for (const g of defaults) this.saveGroup(g);
  }
}
